#define DEFAULT_ORDER 508

typedef struct {
    int value;
} record;

typedef struct {
    int location;
    int indices[DEFAULT_ORDER + 1];
    int keys[DEFAULT_ORDER + 1];
    char is_leaf;
    int num_keys;
} knode;

kernel void findK(
    long maxheight,
    const knode *knodes,
    long knodes_elem,
    const record *records,
    long *currKnode,
    long *offset,
    const int *keys,
    record *ans)
{
    int bid = get_global_id(0) / get_local_size(0);
    int thid = get_local_id(0);
    int threadsPerBlock = get_local_size(0);

    if (bid >= get_global_size(0) / get_local_size(0)) return;

    long current_knode = currKnode[bid];
    long current_offset = offset[bid];
    int key_val = keys[bid];

    for (long i = 0; i < maxheight; i++) {
        if (thid < threadsPerBlock) {
            int k_idx = (int)current_knode;
            if (knodes[k_idx].keys[thid] <= key_val && knodes[k_idx].keys[thid + 1] > key_val) {
                if (knodes[current_offset].indices[thid] < knodes_elem) {
                    current_offset = knodes[current_offset].indices[thid];
                }
            }
        }
        if (thid == 0) {
            current_knode = current_offset;
        }
    }

    if (thid < threadsPerBlock) {
        int k_idx = (int)current_knode;
        if (knodes[k_idx].keys[thid] == key_val) {
            ans[bid].value = records[knodes[k_idx].indices[thid]].value;
        }
    }
}

