    for (long i = 0; i < maxheight; i++) {
        if (thid < threadsPerBlock) {
            int k_idx_curr = (int)current_knode;
            int k_idx_last = (int)last_knode;

            if (knodes[k_idx_curr].keys[thid] <= start_val && knodes[k_idx_curr].keys[thid + 1] > start_val) {
                if (knodes[current_offset].indices[thid] < knodes_elem) {
